singleValueCheck.template:
'use strict';
({params, imports}) => {
  const entity = params.entity;
  const value = entity.getObservationValue('Field Name');
  return value === 'Expected Value';
}

multipleValueCheck.template:
'use strict';
({params, imports}) => {
  const entity = params.entity;
  const value = entity.getObservationValue('Field Name');
  return value === 'Value1' || value === 'Value2';
}

containsCheck.template:
'use strict';
({params, imports}) => {
  const entity = params.entity;
  const values = entity.getObservationValue('Field Name') || [];
  return values.includes('Expected Value');
}

numericComparison.template:
'use strict';
({params, imports}) => {
  const entity = params.entity;
  const value = entity.getObservationValue('Field Name');
  return value > 10;
}

example.rule:
'use strict';
({params, imports}) => {
  const individual = params.entity;
  const beneficiaryType = individual.getObservationValue('Beneficiary Type');
  return beneficiaryType === 'School Students';
}
